mapper.sql:
where r.tenant_id = #{tenantId}
  and r.del_flag = 0

  and r.match_status = #{statusCode}


  and (
    r.reconciliation_no like concat('%', #{keyword}, '%')
    or r.channel_code like concat('%', #{keyword}, '%')
    or r.bill_file_name like concat('%', #{keyword}, '%')
    or r.file_digest like concat('%', #{keyword}, '%')
    or r.importer_name like concat('%', #{keyword}, '%')
  )

mapper.select:

from payment_reconciliation r

order by r.created_at desc
limit #{limit} offset #{offset}


from payment_reconciliation r
where r.tenant_id = #{tenantId}
  and r.id = #{id}
  and r.del_flag = 0
limit 1

select count(1)
from payment_reconciliation r
where r.tenant_id = #{tenantId}
  and r.channel_code = #{channelCode}
  and r.bill_date = #{billDate}
  and r.file_digest = #{fileDigest}
  and r.del_flag = 0
